"""Renderer registry.

Discovers renderers via Python entry points declared in `pyproject.toml` under
the `release_readiness.renderers` group. To add a new renderer:

  1. Create a module under `release_readiness.renderers` that defines a class
     implementing the `Renderer` protocol.
  2. Add an entry under `[project.entry-points."release_readiness.renderers"]`
     in `pyproject.toml` mapping a format name to the class.
  3. Reinstall the package (`pip install -e .`) so setuptools re-reads entry
     points.

The CLI reads `available_formats()` to populate `--format` choices, so a
format not registered here will not be exposed to users.
"""
from __future__ import annotations

from importlib.metadata import entry_points
from typing import TYPE_CHECKING

if TYPE_CHECKING:
    from release_readiness.renderers.base import Renderer

_ENTRY_POINT_GROUP = "release_readiness.renderers"


class RendererRegistry:
    def __init__(self) -> None:
        self._classes: dict[str, type[Renderer]] = {}
        self._load_from_entry_points()

    def _load_from_entry_points(self) -> None:
        for ep in entry_points(group=_ENTRY_POINT_GROUP):
            cls = ep.load()
            self._classes[ep.name] = cls

    def available_formats(self) -> list[str]:
        return sorted(self._classes.keys())

    def get(self, fmt: str) -> Renderer:
        if fmt not in self._classes:
            available = ", ".join(self.available_formats()) or "<none>"
            raise ValueError(f"unknown format {fmt!r}; available: {available}")
        return self._classes[fmt]()

    def register(self, fmt: str, cls: type[Renderer]) -> None:
        """Manually register a renderer. Intended for tests."""
        self._classes[fmt] = cls


# Module-level singleton: built once per process.
_registry: RendererRegistry | None = None


def get_registry() -> RendererRegistry:
    global _registry
    if _registry is None:
        _registry = RendererRegistry()
    return _registry


def reset_registry_for_testing() -> None:
    """Force re-discovery of entry points. Test-only."""
    global _registry
    _registry = None

"""JSON renderer for Report objects."""
from __future__ import annotations

import json

from release_readiness.core.model import Report


class JsonRenderer:
    """Renders a Report as deterministic, sorted JSON."""

    def render(self, report: Report) -> str:
        payload = {
            "title": report.title,
            "sections": [
                {"owner": s.owner, "label": s.label, "count": s.count}
                for s in report.sections
            ],
            "owner_totals": [
                {"owner": ot.owner, "total": ot.total}
                for ot in report.owner_totals
            ],
            "known_owners": list(report.known_owners),
        }
        return json.dumps(payload, sort_keys=True, separators=(",", ":"))

"""Domain model for release-readiness reports."""
from __future__ import annotations

from collections.abc import Iterable
from dataclasses import dataclass, field


@dataclass(frozen=True)
class Section:
    """A single section of the report.

    A section represents one tracked item (a blocked rollout, a hotfix, etc.)
    assigned to an owner. Count is the current queued/outstanding work for
    that item.
    """

    owner: str
    label: str
    count: int

    def __post_init__(self) -> None:
        if not self.owner.strip():
            raise ValueError("owner must be non-empty")
        if not self.label.strip():
            raise ValueError("label must be non-empty")
        if self.count < 0:
            raise ValueError("count must be non-negative")


@dataclass(frozen=True)
class OwnerTotal:
    """Aggregated total per owner across all sections."""

    owner: str
    total: int


@dataclass(frozen=True)
class Report:
    """The fully-aggregated report handed to a renderer."""

    title: str
    sections: tuple[Section, ...]
    owner_totals: tuple[OwnerTotal, ...]
    known_owners: tuple[str, ...] = field(default=())
    """All owners ever seen in the current reporting period, including those
    whose current count is zero. Populated by the aggregation layer."""


def sections_from_iterable(records: Iterable[dict[str, object]]) -> tuple[Section, ...]:
    """Build Section tuples from raw dict records.

    Raises ValueError on malformed records.
    """
    out: list[Section] = []
    for record in records:
        try:
            owner = str(record["owner"])
            label = str(record["label"])
            raw_count = record["count"]
            if not isinstance(raw_count, (int, str)):
                raise TypeError(f"count must be int or str, got {type(raw_count).__name__}")
            count = int(raw_count)
        except (KeyError, TypeError, ValueError) as exc:
            raise ValueError(f"malformed record: {record!r}") from exc
        out.append(Section(owner=owner, label=label, count=count))
    return tuple(out)
